"""
Technical Indicators v2 — добавлены VWAP, Supertrend, Market Regime, MFI
"""

import numpy as np
from typing import Tuple, Dict, Any
from datetime import datetime, timezone


def calculate_atr_percent(high: np.ndarray, low: np.ndarray, close: np.ndarray, period: int = 14) -> float:
    if len(high) < period:
        return 0.0
    prev_close = np.concatenate(([close[0]], close[:-1]))
    tr = np.maximum(high - low, np.maximum(np.abs(high - prev_close), np.abs(low - prev_close)))
    atr = np.mean(tr[-period:])
    return float((atr / close[-1]) * 100) if close[-1] != 0 else 0.0


def calculate_rsi(prices: np.ndarray, period: int = 14) -> float:
    if len(prices) < period + 1:
        return 50.0
    deltas = np.diff(prices)
    gains = np.where(deltas > 0, deltas, 0)
    losses = np.where(deltas < 0, -deltas, 0)
    avg_gain = np.mean(gains[:period])
    avg_loss = np.mean(losses[:period])
    if avg_loss == 0:
        return 100.0
    rs = avg_gain / avg_loss
    return float(100 - (100 / (1 + rs)))


def calculate_ema(prices: np.ndarray, period: int) -> float:
    if len(prices) < period:
        return float(prices[-1]) if len(prices) > 0 else 0.0
    k = 2 / (period + 1)
    ema = np.mean(prices[:period])
    for price in prices[period:]:
        ema = price * k + ema * (1 - k)
    return float(ema)


def calculate_adx(high: np.ndarray, low: np.ndarray, close: np.ndarray, period: int = 14) -> Tuple[float, float, float]:
    if len(close) < period + 1:
        return 0.0, 0.0, 0.0

    tr1 = high[1:] - low[1:]
    tr2 = np.abs(high[1:] - close[:-1])
    tr3 = np.abs(low[1:] - close[:-1])
    tr = np.maximum(np.maximum(tr1, tr2), tr3)

    plus_dm = np.where((high[1:] - high[:-1]) > (low[:-1] - low[1:]), high[1:] - high[:-1], 0)
    minus_dm = np.where((low[:-1] - low[1:]) > (high[1:] - high[:-1]), low[:-1] - low[1:], 0)

    atr = _wilder_smooth(tr, period)
    plus_di = 100 * _wilder_smooth(plus_dm, period) / (atr + 1e-10)
    minus_di = 100 * _wilder_smooth(minus_dm, period) / (atr + 1e-10)
    dx = 100 * np.abs(plus_di - minus_di) / (plus_di + minus_di + 1e-10)
    adx = _wilder_smooth(dx, period)

    return float(adx[-1]), float(plus_di[-1]), float(minus_di[-1])


def _wilder_smooth(data: np.ndarray, period: int) -> np.ndarray:
    result = np.zeros_like(data)
    result[:period] = np.mean(data[:period])
    for i in range(period, len(data)):
        result[i] = (result[i-1] * (period - 1) + data[i]) / period
    return result


def calculate_bollinger_bands(close: np.ndarray, period: int = 20, std_dev: float = 2.0) -> Dict[str, float]:
    if len(close) < period:
        return {}
    sma = np.mean(close[-period:])
    std = np.std(close[-period:])
    return {'upper': sma + std_dev * std, 'middle': sma, 'lower': sma - std_dev * std}


def calculate_macd(close: np.ndarray, fast: int = 12, slow: int = 26, signal: int = 9) -> Tuple[float, float, float]:
    ema_fast = calculate_ema(close, fast)
    ema_slow = calculate_ema(close, slow)
    macd_line = ema_fast - ema_slow
    signal_line = macd_line
    return float(macd_line), float(signal_line), float(macd_line - signal_line)


def calculate_ichimoku(high: np.ndarray, low: np.ndarray, close: np.ndarray,
                       tenkan: int = 9, kijun: int = 26, senkou: int = 52) -> Dict[str, float]:
    if len(close) < max(tenkan, kijun, senkou):
        return {}
    tenkan_sen = (np.max(high[-tenkan:]) + np.min(low[-tenkan:])) / 2
    kijun_sen = (np.max(high[-kijun:]) + np.min(low[-kijun:])) / 2
    senkou_a = (tenkan_sen + kijun_sen) / 2
    senkou_b = (np.max(high[-senkou:]) + np.min(low[-senkou:])) / 2
    return {"tenkan_sen": tenkan_sen, "kijun_sen": kijun_sen, "senkou_span_a": senkou_a, "senkou_span_b": senkou_b}


def get_trend_score(ema_fast: float, ema_slow: float) -> int:
    return 1 if ema_fast > ema_slow else (-1 if ema_fast < ema_slow else 0)


def calculate_volume_score(volume: np.ndarray, current_vol: float) -> float:
    if len(volume) >= 20:
        mean_vol = np.mean(volume[-20:])
    else:
        mean_vol = np.mean(volume) if len(volume) > 0 else current_vol
    if mean_vol == 0:
        return 0.5
    return min(current_vol / mean_vol, 2.0) / 2.0


def calculate_vwap(high: np.ndarray, low: np.ndarray, close: np.ndarray, volume: np.ndarray) -> Dict[str, float]:
    if len(close) < 20:
        return {'vwap': close[-1], 'upper': close[-1], 'lower': close[-1], 'deviation': 0}
    typical = (high + low + close) / 3
    vwap = np.cumsum(typical * volume) / np.cumsum(volume)
    variance = np.cumsum((typical - vwap) ** 2 * volume) / np.cumsum(volume)
    std = np.sqrt(variance)
    current_vwap = vwap[-1]
    current_std = std[-1]
    return {
        'vwap': float(current_vwap),
        'upper': float(current_vwap + 2 * current_std),
        'lower': float(current_vwap - 2 * current_std),
        'deviation': float((close[-1] - current_vwap) / (current_std + 1e-9) * 100)
    }


def calculate_supertrend(high: np.ndarray, low: np.ndarray, close: np.ndarray, 
                         period: int = 10, multiplier: float = 3.0) -> Dict[str, Any]:
    if len(close) < period + 1:
        return {'direction': 0, 'supertrend': close[-1], 'upper': close[-1], 'lower': close[-1]}
    prev_close = np.concatenate(([close[0]], close[:-1]))
    tr = np.maximum(high - low, np.maximum(np.abs(high - prev_close), np.abs(low - prev_close)))
    atr = np.zeros_like(tr)
    atr[:period] = np.mean(tr[:period])
    for i in range(period, len(tr)):
        atr[i] = (atr[i-1] * (period - 1) + tr[i]) / period
    hl2 = (high + low) / 2
    upper = hl2 + multiplier * atr
    lower = hl2 - multiplier * atr
    st = np.zeros_like(close)
    st[0] = close[0]
    for i in range(1, len(close)):
        if close[i] > st[i-1]:
            st[i] = max(lower[i], st[i-1])
        else:
            st[i] = min(upper[i], st[i-1])
    direction = 1 if close[-1] > st[-1] else -1
    return {
        'direction': direction,
        'supertrend': float(st[-1]),
        'upper': float(upper[-1]),
        'lower': float(lower[-1])
    }


def calculate_mfi(high: np.ndarray, low: np.ndarray, close: np.ndarray, 
                  volume: np.ndarray, period: int = 14) -> float:
    if len(close) < period + 1:
        return 50.0
    typical = (high + low + close) / 3
    raw_money_flow = typical * volume
    money_flow = np.where(np.diff(typical, prepend=typical[0]) > 0, raw_money_flow, -raw_money_flow)
    positive_flow = np.where(money_flow > 0, money_flow, 0)
    negative_flow = np.where(money_flow < 0, -money_flow, 0)
    pos_sum = np.sum(positive_flow[-period:])
    neg_sum = np.sum(negative_flow[-period:])
    if neg_sum == 0:
        return 100.0
    mfi = 100 - (100 / (1 + pos_sum / neg_sum))
    return float(mfi)


def calculate_market_regime(close: np.ndarray, volume: np.ndarray = None) -> str:
    if len(close) < 50:
        return "UNKNOWN"
    ema20 = _calculate_ema_array(close, 20)
    ema50 = _calculate_ema_array(close, 50)
    price = close[-1]
    e20 = ema20[-1]
    e50 = ema50[-1]
    if price > e20 > e50:
        return "BULL"
    elif price < e20 < e50:
        return "BEAR"
    else:
        return "CHOP"


def _calculate_ema_array(data: np.ndarray, period: int) -> np.ndarray:
    k = 2 / (period + 1)
    ema = np.zeros_like(data)
    ema[0] = data[0]
    for i in range(1, len(data)):
        ema[i] = data[i] * k + ema[i-1] * (1 - k)
    return ema


def calculate_session_bonus() -> float:
    hour = datetime.now(timezone.utc).hour
    if 13 <= hour <= 16:
        return 1.2
    elif 17 <= hour <= 21:
        return 1.3
    elif 1 <= hour <= 8:
        return 0.9
    elif 0 <= hour < 6:
        return 0.5
    else:
        return 1.0


def calculate_chandelier_exit(high: np.ndarray, low: np.ndarray, close: np.ndarray,
                               period: int = 22, multiplier: float = 3.0) -> Dict[str, float]:
    if len(close) < period:
        return {'long_stop': close[-1], 'short_stop': close[-1], 'direction': 0}
    atr = np.zeros(len(close))
    tr = np.maximum(high[1:] - low[1:], 
                    np.maximum(np.abs(high[1:] - close[:-1]), np.abs(low[1:] - close[:-1])))
    atr[0] = tr[0]
    for i in range(1, len(tr)):
        atr[i] = (atr[i-1] * (period - 1) + tr[i]) / period
    highest_high = np.max(high[-period:])
    lowest_low = np.min(low[-period:])
    long_stop = highest_high - multiplier * atr[-1]
    short_stop = lowest_low + multiplier * atr[-1]
    return {
        'long_stop': float(long_stop),
        'short_stop': float(short_stop),
        'direction': 1 if close[-1] > long_stop else -1
    }

