"""
Risk Controller – консервативное управление рисками с корреляционным лимитом и дневными целями.
"""

import time
from typing import Dict, List, Tuple, Optional
from datetime import datetime, timedelta

from src.core.logger import BotLogger
from src.core.trading.position import Position


class RiskController:
    def __init__(self, logger: BotLogger, config: Dict):
        self.logger = logger
        self.config = config

        self.daily_loss_limit_percent = config.get("daily_loss_limit_percent", 8.0)
        self.daily_pnl = 0.0
        self.daily_start_balance = None
        self.circuit_breaker_active = False
        self.circuit_breaker_until = None

        self.max_orders_per_hour = config.get("max_orders_per_hour", 6)
        self.orders_timestamps: List[float] = []

        self.anti_martingale_enabled = config.get("anti_martingale_enabled", True)
        self.anti_martingale_reduction = config.get("anti_martingale_risk_reduction", 0.8)
        self.base_risk_per_trade = config.get("max_risk_per_trade", 1.0)

        self.max_total_risk_percent = config.get("max_total_risk_percent", 15.0)
        self.max_positions = config.get("max_positions", 2)

        self.correlation_groups = config.get("correlation_groups", {
            "btc_eth": ["BTC/USDT", "ETH/USDT"],
            "layer1": ["BNB/USDT", "SOL/USDT", "AVAX/USDT"],
            "meme": ["DOGE/USDT", "SHIB/USDT", "PEPE/USDT"]
        })
        self.open_categories: Dict[str, int] = {}
        self.correlation_limit_enabled = config.get("correlation_limit_enabled", True)

        self.consecutive_losses = 0
        self.win_streak = 0
        self.win_rate = 50.0
        self.avg_win = 0.0
        self.avg_loss = 0.0
        self.total_trades = 0
        self.wins = 0
        self.losses = 0

        self.unrealized_drawdown_limit = config.get("unrealized_drawdown_limit_percent", 12.0)
        self.max_margin_percent = config.get("max_margin_percent", 50.0)

    def apply_anti_martingale(self, pnl: float, base_risk: float) -> float:
        if pnl < 0 and self.anti_martingale_enabled:
            new_risk = base_risk * self.anti_martingale_reduction
            return max(0.3, new_risk)
        return base_risk

    def register_order(self):
        now = time.time()
        self.orders_timestamps = [t for t in self.orders_timestamps if now - t < 3600]
        self.orders_timestamps.append(now)

    def add_pnl(self, pnl: float):
        self.daily_pnl += pnl
        if pnl > 0:
            self.win_streak += 1
            self.consecutive_losses = 0
            self.wins += 1
        else:
            self.win_streak = 0
            self.consecutive_losses += 1
            self.losses += 1
        self.total_trades += 1
        if self.total_trades > 0:
            self.win_rate = (self.wins / self.total_trades) * 100

    def get_staged_risk(self, balance: float) -> Tuple[float, int, int]:
        stages = self.config.get("stages", [
            {"balance_up_to": 200, "risk_percent": 0.8, "leverage": 2},
            {"balance_up_to": 500, "risk_percent": 0.7, "leverage": 2},
            {"balance_up_to": 1000, "risk_percent": 0.6, "leverage": 2}
        ])
        for stage in stages:
            if balance <= stage["balance_up_to"]:
                return stage["risk_percent"], stage["leverage"], self.max_positions
        return 0.5, 2, self.max_positions

    def check_circuit_breaker(self, current_balance: float) -> Tuple[bool, str]:
        if self.circuit_breaker_active:
            if datetime.now() < self.circuit_breaker_until:
                return False, f"Circuit breaker до {self.circuit_breaker_until.strftime('%H:%M')}"
            else:
                self.circuit_breaker_active = False

        if self.daily_start_balance is None or self.daily_start_balance <= 0:
            return True, ""

        daily_pnl_pct = (self.daily_pnl / self.daily_start_balance) * 100
        if daily_pnl_pct <= -self.daily_loss_limit_percent:
            self.circuit_breaker_active = True
            self.circuit_breaker_until = datetime.now().replace(hour=0, minute=0, second=0) + timedelta(days=1)
            self.logger.error(f"Дневной убыток {daily_pnl_pct:.1f}%. Торговля остановлена.")
            return False, f"Лимит -{self.daily_loss_limit_percent}% превышен"
        return True, ""

    def can_open_new_position(self, open_positions_count: int, balance: float,
                              current_total_risk: float, new_position_risk: float,
                              symbol: str = None) -> Tuple[bool, str]:
        if open_positions_count >= self.max_positions:
            return False, f"Лимит позиций ({self.max_positions})"
        can_proceed, reason = self.check_circuit_breaker(balance)
        if not can_proceed:
            return False, reason
        if len(self.orders_timestamps) >= self.max_orders_per_hour:
            return False, f"Лимит ордеров в час ({self.max_orders_per_hour})"
        if symbol and not self.can_open_in_category(symbol):
            return False, f"Корреляционный лимит для {symbol}"
        return True, ""

    def calculate_total_risk(self, positions: Dict[str, Position]) -> float:
        total = 0.0
        for pos in positions.values():
            active_stop = pos._get_active_stop()
            total += pos.remaining_quantity * abs(pos.entry_price - active_stop)
        return total

    def get_category(self, symbol: str) -> str:
        for cat, symbols in self.correlation_groups.items():
            if symbol in symbols:
                return cat
        return "other"

    def can_open_in_category(self, symbol: str) -> bool:
        if not self.correlation_limit_enabled:
            return True
        cat = self.get_category(symbol)
        return self.open_categories.get(cat, 0) < 1

    def register_position_open(self, symbol: str):
        cat = self.get_category(symbol)
        self.open_categories[cat] = self.open_categories.get(cat, 0) + 1

    def register_position_close(self, symbol: str):
        cat = self.get_category(symbol)
        if cat in self.open_categories:
            self.open_categories[cat] = max(0, self.open_categories[cat] - 1)

    def emergency_close_all(self, open_positions, order_manager) -> float:
        total_pnl = 0.0
        for sym in list(open_positions.keys()):
            if order_manager.close_position(sym):
                pos = open_positions[sym]
                pnl = pos.close_full()
                total_pnl += pnl
                del open_positions[sym]
        return total_pnl

    def is_sideways_market(self, adx: float, bb_upper: float, bb_lower: float, close: float) -> bool:
        if adx >= 20:
            return False
        if bb_upper and bb_lower and close:
            bb_width = ((bb_upper - bb_lower) / close) * 100
            return bb_width < 4.0
        return False

    def reset_daily(self):
        self.daily_pnl = 0.0
        self.daily_start_balance = None
        self.orders_timestamps.clear()
        self.circuit_breaker_active = False

