"""
Signal Evaluator – оценка сигналов с мультитаймфреймом.
"""

from typing import Dict, Tuple, Optional
from src.config.constants import SignalDirection
from src.core.signals.candle_patterns import evaluate_candle_bonus


class SignalEvaluator:
    def __init__(self, config: Optional[Dict] = None):
        self.config = config or {}
        self.min_adx_trend = self.config.get("min_adx", 20)
        self.multi_tf_weights = {
            "15m": 0.20, "1h": 0.30, "4h": 0.30, "1d": 0.20
        }

    def _evaluate_single_tf(self, indicators: Dict) -> Tuple[str, float, Dict]:
        rsi = indicators.get('rsi', 50)
        adx = indicators.get('adx', 0)
        trend_score = indicators.get('trend_score', 0)

        base_strength = 0.4 + (adx / 100) * 0.5
        direction = "NEUTRAL"

        if adx >= self.min_adx_trend and abs(trend_score) > 0:
            direction = "BUY" if trend_score > 0 else "SELL"
        elif rsi <= 30:
            direction = "BUY"
            base_strength = 0.6
        elif rsi >= 70:
            direction = "SELL"
            base_strength = 0.6

        if direction == "NEUTRAL":
            return "NEUTRAL", 0.0, {}

        strength_multiplier = 1.0

        vwap_dev = abs(indicators.get('deviation', 0))
        if vwap_dev > 50:
            strength_multiplier *= 1.2
        elif vwap_dev < 20:
            strength_multiplier *= 0.8

        st_dir = indicators.get('supertrend_direction', 0)
        if (direction == "BUY" and st_dir == 1) or (direction == "SELL" and st_dir == -1):
            strength_multiplier *= 1.25
        elif st_dir != 0:
            strength_multiplier *= 0.7

        mfi = indicators.get('mfi', 50)
        if direction == "BUY" and mfi < 40:
            strength_multiplier *= 1.15
        elif direction == "SELL" and mfi > 60:
            strength_multiplier *= 1.15
        elif (direction == "BUY" and mfi > 60) or (direction == "SELL" and mfi < 40):
            strength_multiplier *= 0.85

        regime = indicators.get('market_regime', 'CHOP')
        if regime == 'CHOP':
            strength_multiplier *= 0.7
        elif (direction == "BUY" and regime == 'BULL') or (direction == "SELL" and regime == 'BEAR'):
            strength_multiplier *= 1.2

        final_strength = min(0.95, base_strength * strength_multiplier)

        return direction, final_strength, {'entry_type': 'trend_following'}

    def evaluate(self, indicators: Dict,
                 multi_tf_data: Optional[Dict[str, Dict]] = None) -> Tuple[SignalDirection, float, Dict]:
        base_dir, base_strength, base_details = self._evaluate_single_tf(indicators)

        if not multi_tf_data:
            if base_dir == "NEUTRAL" or base_strength < 0.35:
                return SignalDirection.NEUTRAL, 0.0, {}
            return SignalDirection.BUY if base_dir == "BUY" else SignalDirection.SELL, base_strength, base_details

        tf_signals = {}
        for tf, ind in multi_tf_data.items():
            if ind:
                d, s, _ = self._evaluate_single_tf(ind)
                if d != "NEUTRAL":
                    tf_signals[tf] = {'dir': d, 'strength': s}

        buy_weight = sell_weight = total_weight = 0.0
        for tf, sig in tf_signals.items():
            w = self.multi_tf_weights.get(tf, 0.2)
            total_weight += w
            if sig['dir'] == "BUY":
                buy_weight += w * sig['strength']
            else:
                sell_weight += w * sig['strength']

        if base_dir != "NEUTRAL":
            total_weight += 0.5
            if base_dir == "BUY":
                buy_weight += 0.5 * base_strength
            else:
                sell_weight += 0.5 * base_strength

        if total_weight == 0:
            return SignalDirection.NEUTRAL, 0.0, {}

        buy_ratio = buy_weight / total_weight
        sell_ratio = sell_weight / total_weight

        if buy_ratio > sell_ratio and buy_ratio > 0.3:
            final_dir, final_strength = "BUY", min(0.95, buy_ratio)
        elif sell_ratio > buy_ratio and sell_ratio > 0.3:
            final_dir, final_strength = "SELL", min(0.95, sell_ratio)
        else:
            return SignalDirection.NEUTRAL, 0.0, {}

        candle_bonus = evaluate_candle_bonus(
            open_price=indicators.get('open_price', 0),
            high=indicators.get('high_price', 0),
            low=indicators.get('low_price', 0),
            close=indicators.get('close_price', 0),
            direction=final_dir
        )
        final_strength = min(final_strength + candle_bonus * 0.3, 0.95)

        return SignalDirection.BUY if final_dir == "BUY" else SignalDirection.SELL, final_strength, {'entry_type': 'multi_timeframe'}

