"""
Position – класс позиции с трейлингом и ступенчатым TP.
"""

from datetime import datetime, timedelta
from dataclasses import dataclass, field
from typing import List, Dict, Tuple

from src.config.constants import OrderSide


@dataclass
class Position:
    symbol: str
    side: OrderSide
    quantity: float
    entry_price: float
    leverage: int
    stop_loss_price: float
    take_profit_price: float
    timestamp: datetime = field(default_factory=datetime.now)

    current_price: float = 0.0
    trailing_stop_activated: bool = False
    trailing_stop_price: float = 0.0
    highest_price: float = 0.0
    lowest_price: float = float('inf')
    remaining_quantity: float = 0.0

    atr_entry: float = 0.0
    rsi_entry: float = 50.0
    adx_entry: float = 20.0

    stepped_tp_levels: List[Dict] = field(default_factory=list)
    stepped_tp_index: int = 0

    strategy_type: str = "trend_following"
    dead_weight_start: datetime = None

    _close_attempts: int = field(default=0, repr=False)

    def __post_init__(self):
        if self.entry_price is None or self.entry_price <= 0:
            self.entry_price = 0.00000001
        if abs(self.entry_price) < 1e-10:
            self.entry_price = 0.00000001

        if self.side == OrderSide.BUY:
            self.highest_price = self.entry_price
        else:
            self.lowest_price = self.entry_price

        if self.remaining_quantity == 0.0:
            self.remaining_quantity = self.quantity

    def update_market_price(self, price: float):
        self.current_price = price
        if self.side == OrderSide.BUY and price > self.highest_price:
            self.highest_price = price
        elif self.side == OrderSide.SELL and price < self.lowest_price:
            self.lowest_price = price

    def calculate_unrealized_pnl(self) -> float:
        if self.side == OrderSide.BUY:
            return (self.current_price - self.entry_price) * self.remaining_quantity * self.leverage
        else:
            return (self.entry_price - self.current_price) * self.remaining_quantity * self.leverage

    def calculate_unrealized_pnl_at_price(self, price: float) -> float:
        if self.side == OrderSide.BUY:
            return (price - self.entry_price) * self.remaining_quantity * self.leverage
        else:
            return (self.entry_price - price) * self.remaining_quantity * self.leverage

    def calculate_pnl_percent(self) -> float:
        if self.entry_price is None or abs(self.entry_price) < 1e-10:
            return 0.0
        if self.side == OrderSide.BUY:
            return ((self.current_price - self.entry_price) / self.entry_price) * 100
        else:
            return ((self.entry_price - self.current_price) / self.entry_price) * 100

    def _get_active_stop(self) -> float:
        if self.trailing_stop_activated and self.trailing_stop_price > 0:
            return self.trailing_stop_price
        return self.stop_loss_price

    def should_exit_by_stop_loss(self) -> bool:
        active = self._get_active_stop()
        if self.side == OrderSide.BUY:
            return self.current_price <= active
        return self.current_price >= active

    def should_exit_by_take_profit(self) -> bool:
        if self.side == OrderSide.BUY:
            return self.current_price >= self.take_profit_price
        return self.current_price <= self.take_profit_price

    def update_trailing_stop(self, distance_percent: float):
        profit_pct = self.calculate_pnl_percent()
        if profit_pct < 1.0:
            return
        if self.side == OrderSide.BUY:
            new_stop = self.highest_price * (1 - distance_percent / 100)
            if not self.trailing_stop_activated or new_stop > self.trailing_stop_price:
                self.trailing_stop_activated = True
                self.trailing_stop_price = new_stop
        else:
            new_stop = self.lowest_price * (1 + distance_percent / 100)
            if not self.trailing_stop_activated or new_stop < self.trailing_stop_price:
                self.trailing_stop_activated = True
                self.trailing_stop_price = new_stop

    def apply_stepped_take_profit(self, min_qty: float) -> Tuple[float, bool]:
        if not self.stepped_tp_levels or self.stepped_tp_index >= len(self.stepped_tp_levels):
            return 0.0, False
        profit_pct = self.calculate_pnl_percent()
        level = self.stepped_tp_levels[self.stepped_tp_index]
        if profit_pct >= level["profit_percent"]:
            close_qty = self.remaining_quantity * level["close_ratio"]
            pnl = self.calculate_unrealized_pnl() * level["close_ratio"]
            self.remaining_quantity -= close_qty
            self.stepped_tp_index += 1
            return pnl, self.remaining_quantity < min_qty
        return 0.0, False

    def is_dead_weight(self, range_percent: float, max_hours: int) -> bool:
        if abs(self.calculate_pnl_percent()) > range_percent:
            self.dead_weight_start = None
            return False
        if self.dead_weight_start is None:
            self.dead_weight_start = datetime.now()
            return False
        return datetime.now() - self.dead_weight_start > timedelta(hours=max_hours)

    def close_full(self) -> float:
        return self.calculate_unrealized_pnl()

    def to_dict(self) -> Dict:
        return {
            "symbol": self.symbol,
            "side": self.side.value,
            "quantity": self.quantity,
            "entry_price": self.entry_price,
            "leverage": self.leverage,
            "stop_loss_price": self.stop_loss_price,
            "take_profit_price": self.take_profit_price,
            "timestamp": self.timestamp.isoformat(),
            "current_price": self.current_price,
            "trailing_stop_activated": self.trailing_stop_activated,
            "trailing_stop_price": self.trailing_stop_price,
            "highest_price": self.highest_price,
            "lowest_price": self.lowest_price,
            "remaining_quantity": self.remaining_quantity,
            "atr_entry": self.atr_entry,
            "rsi_entry": self.rsi_entry,
            "adx_entry": self.adx_entry,
            "stepped_tp_index": self.stepped_tp_index,
            "strategy_type": self.strategy_type,
        }

