"""
BingX API Client v5 — стабильная версия с исправлениями.
"""

import ccxt
import time
import hmac
import hashlib
import urllib.parse
import requests
from requests.adapters import HTTPAdapter
from urllib3.util.retry import Retry
import json
import math
from typing import Dict, List, Optional, Any

from src.core.logger import BotLogger


class BingXClient:
    def __init__(self, api_key: str, api_secret: str, demo_mode: bool = True, settings: Dict = None):
        self.api_key = api_key
        self.api_secret = api_secret
        self.demo_mode = demo_mode
        self.settings = settings or {}
        self.max_retries = 3
        self.retry_delay = 1.0
        self.timeout = 15
        self.logger = BotLogger(level="INFO")
        self.profiler = None

        self.base_url = 'https://open-api-vst.bingx.com' if demo_mode else 'https://open-api.bingx.com'

        self.session = requests.Session()
        retry_strategy = Retry(
            total=3,
            backoff_factor=0.5,
            status_forcelist=[429, 500, 502, 503, 504],
            allowed_methods=["GET", "POST"]
        )
        adapter = HTTPAdapter(max_retries=retry_strategy, pool_connections=50, pool_maxsize=50)
        self.session.mount("https://", adapter)
        self.session.mount("http://", adapter)

        self.server_time_offset = 0
        self._sync_server_time()

        config = {
            'apiKey': api_key,
            'secret': api_secret,
            'options': {'defaultType': 'swap'},
            'enableRateLimit': True,
            'timeout': self.timeout * 1000,
        }
        if demo_mode:
            config['options']['test'] = True
            config['urls'] = {
                'api': {
                    'public': 'https://open-api-vst.bingx.com',
                    'private': 'https://open-api-vst.bingx.com',
                }
            }

        self.exchange = ccxt.bingx(config)
        try:
            self.exchange.load_markets()
            self.logger.info("Рынки загружены (ccxt)")
        except Exception as e:
            self.logger.warning(f"Не удалось загрузить рынки: {e}")

    def set_profiler(self, profiler):
        self.profiler = profiler

    def _sync_server_time(self):
        try:
            url = self.base_url + "/openApi/swap/v2/server/time"
            resp = self.session.get(url, timeout=5)
            data = resp.json()
            if data.get('code') == 0:
                server_time = int(data['data']['serverTime'])
                local_time = int(time.time() * 1000)
                self.server_time_offset = server_time - local_time
                self.logger.info(f"Синхронизация времени: offset={self.server_time_offset}ms")
        except Exception as e:
            self.logger.warning(f"Не удалось синхронизировать время: {e}")

    def _get_timestamp(self) -> str:
        return str(int(time.time() * 1000) + self.server_time_offset)

    def _sign(self, params: Dict) -> str:
        query = urllib.parse.urlencode(params)
        return hmac.new(self.api_secret.encode('utf-8'), query.encode('utf-8'), hashlib.sha256).hexdigest()

    def _request(self, endpoint: str, params: Dict = None, method: str = 'POST') -> Dict:
        url = self.base_url + endpoint
        headers = {
            'X-BX-APIKEY': self.api_key,
            'Content-Type': 'application/x-www-form-urlencoded'
        }

        for attempt in range(self.max_retries):
            req_params = params.copy() if params else {}
            req_params['timestamp'] = self._get_timestamp()
            req_params['signature'] = self._sign(req_params)

            try:
                if method.upper() == 'GET':
                    resp = self.session.get(url, params=req_params, headers=headers, timeout=self.timeout)
                else:
                    resp = self.session.post(url, data=req_params, headers=headers, timeout=self.timeout)

                data = resp.json()

                if data.get('code') != 0:
                    error_msg = data.get('msg', 'Unknown error')
                    error_code = data.get('code', 0)

                    if 'timestamp' in error_msg.lower() or error_code == 100400:
                        self.logger.warning(f"Timestamp error, resyncing...")
                        self._sync_server_time()
                        if attempt < self.max_retries - 1:
                            continue

                    if error_code == 101204 or 'insufficient margin' in error_msg.lower():
                        self.logger.error(f"Insufficient margin error: {error_msg}")
                        raise Exception(f"API error {error_code}: {error_msg}")

                    if any(x in error_msg.lower() for x in ['already', 'уже', 'not modified']):
                        return data.get('data', {})

                    raise Exception(f"API error {error_code}: {error_msg}")

                return data.get('data', {})

            except Exception as e:
                if attempt == self.max_retries - 1:
                    raise
                self.logger.warning(f"API retry {attempt + 1}/{self.max_retries}: {e}")
                time.sleep(self.retry_delay * (attempt + 1))

        return {}

    def _convert_precision(self, prec) -> int:
        if isinstance(prec, float) and 0 < prec < 1:
            return max(0, int(round(-math.log10(prec))))
        return int(prec) if prec else 4

    def get_all_contracts(self) -> List[Dict]:
        markets = self.exchange.fetch_markets()
        result = []
        for m in markets:
            if not (m.get('swap') and m.get('quote') == 'USDT' and m.get('active')):
                continue
            price_prec = self._convert_precision(m['precision']['price'])
            qty_prec = self._convert_precision(m['precision']['amount'])
            result.append({
                "symbol": m['symbol'],
                "minQty": m['limits']['amount']['min'] or 0.001,
                "maxQty": m['limits']['amount']['max'] or 1000000,
                "pricePrecision": price_prec,
                "quantityPrecision": qty_prec,
                "stepSize": m['limits']['amount']['min'] or 0.001
            })
        return result

    def get_ticker(self, symbol: str) -> Dict:
        try:
            ticker = self.exchange.fetch_ticker(symbol)
            return {
                "symbol": symbol,
                "lastPrice": ticker.get('last', 0),
                "volume24h": ticker.get('quoteVolume', 0),
                "high24h": ticker.get('high', 0),
                "low24h": ticker.get('low', 0),
                "markPrice": ticker.get('info', {}).get('markPrice', ticker.get('last', 0))
            }
        except Exception:
            return {"symbol": symbol, "lastPrice": 0, "volume24h": 0}

    def get_klines(self, symbol: str, interval: str = "1h", limit: int = 100) -> List:
        try:
            return self.exchange.fetch_ohlcv(symbol, timeframe=interval, limit=limit)
        except Exception:
            return []

    def get_funding_rate(self, symbol: str) -> Dict:
        try:
            base_symbol = symbol.replace('/USDT', '-USDT')
            params = {'symbol': base_symbol, 'timestamp': self._get_timestamp()}
            params['signature'] = self._sign(params)
            url = self.base_url + "/openApi/swap/v2/quote/premiumIndex"
            headers = {'X-BX-APIKEY': self.api_key}
            resp = self.session.get(url, params=params, headers=headers, timeout=self.timeout)
            data = resp.json()
            if data.get('code') == 0:
                return {"fundingRate": float(data.get('data', {}).get('lastFundingRate', 0))}
            return {"fundingRate": 0}
        except Exception:
            return {"fundingRate": 0}

    def get_order_book(self, symbol: str, limit: int = 5) -> Dict:
        try:
            ob = self.exchange.fetch_order_book(symbol, limit)
            return {"bids": ob['bids'][:limit], "asks": ob['asks'][:limit]}
        except Exception:
            return {"bids": [], "asks": []}

    def get_account_info(self) -> Optional[Dict]:
        try:
            params = {'timestamp': self._get_timestamp()}
            params['signature'] = self._sign(params)
            url = self.base_url + "/openApi/swap/v2/user/balance"
            headers = {'X-BX-APIKEY': self.api_key, 'Content-Type': 'application/x-www-form-urlencoded'}

            resp = self.session.get(url, params=params, headers=headers, timeout=self.timeout)
            data = resp.json()

            if data.get('code') != 0:
                raise Exception(f"API error {data.get('code')}: {data.get('msg')}")

            balance_obj = data.get('data', {}).get('balance', {})
            total = float(balance_obj.get('balance', 0))
            available = float(balance_obj.get('availableMargin', 0))
            used = float(balance_obj.get('usedMargin', 0))

            return {"balance": total, "available": available, "used": used}
        except Exception as e:
            self.logger.error(f"Ошибка получения баланса: {e}")
            return None

    def get_positions(self) -> List[Dict]:
        try:
            data = self._request("/openApi/swap/v2/user/positions", {}, 'GET')
            if not isinstance(data, list):
                data = [data] if data else []
            result = []
            for p in data:
                amt = float(p.get('positionAmt', 0))
                if amt != 0:
                    result.append({
                        "symbol": p['symbol'].replace('-USDT', '/USDT'),
                        "positionAmt": amt,
                        "avgPrice": float(p.get('avgPrice', 0)),
                        "positionSide": p.get('positionSide', 'LONG'),
                        "leverage": int(p.get('leverage', 1)),
                        "unrealizedProfit": float(p.get('unrealizedProfit', 0)),
                        "markPrice": float(p.get('markPrice', 0)),
                        "lastPrice": float(p.get('lastPrice', 0))
                    })
            return result
        except Exception as e:
            self.logger.error(f"Ошибка получения позиций: {e}")
            return []

    def set_leverage(self, symbol: str, leverage: int, side: str = "LONG") -> Dict:
        base_symbol = symbol.replace('/USDT', '-USDT')
        try:
            self._request("/openApi/swap/v2/trade/leverage", {
                'symbol': base_symbol,
                'leverage': str(leverage),
                'side': side.upper()
            })
            self.logger.info(f"Плечо {leverage}x {side} для {symbol}")
            return {"leverage": leverage}
        except Exception as e:
            if 'already' in str(e).lower():
                return {"leverage": leverage}
            self.logger.error(f"Ошибка установки плеча: {e}")
            return {"leverage": leverage}

    def set_margin_mode(self, symbol: str, margin_mode: str = 'cross') -> bool:
        base_symbol = symbol.replace('/USDT', '-USDT')
        margin_type = 'CROSSED' if margin_mode.lower() == 'cross' else 'ISOLATED'
        try:
            self._request("/openApi/swap/v2/trade/marginType", {
                'symbol': base_symbol,
                'marginType': margin_type,
                'marginCoin': 'USDT'
            })
            self.logger.info(f"Режим маржи {margin_type} для {symbol}")
            return True
        except Exception as e:
            if 'already' in str(e).lower():
                return True
            self.logger.warning(f"Ошибка установки маржи: {e}")
            return False

    def _get_price_precision(self, symbol: str) -> int:
        try:
            market = self.exchange.market(symbol)
            return self._convert_precision(market['precision']['price'])
        except:
            return 4

    def _get_qty_precision(self, symbol: str) -> int:
        try:
            market = self.exchange.market(symbol)
            return self._convert_precision(market['precision']['amount'])
        except:
            return 4

    def _format_stop_obj(self, price: float, precision: int, obj_type: str) -> str:
        price_val = round(float(price), precision)
        obj = {
            "type": obj_type,
            "stopPrice": price_val,
            "price": price_val,
            "workingType": "MARK_PRICE"
        }
        return json.dumps(obj, ensure_ascii=False)

    def cancel_all_orders(self, symbol: str) -> bool:
        try:
            self.exchange.cancel_all_orders(symbol)
            self.logger.debug(f"Все ордера отменены для {symbol}")
            time.sleep(0.3)
            return True
        except Exception as e:
            msg = str(e).lower()
            if any(x in msg for x in ['no orders', 'not found', 'empty', 'no open']):
                return True
            self.logger.error(f"Ошибка отмены ордеров {symbol}: {e}")
            return False

    def close_position_with_cleanup(self, symbol: str, position_side: str = "LONG") -> bool:
        base_symbol = symbol.replace('/USDT', '-USDT')
        self.cancel_all_orders(symbol)
        time.sleep(0.3)

        positions = self.get_positions()
        position = next((p for p in positions if p['symbol'] == symbol), None)
        if not position or float(position.get('positionAmt', 0)) == 0:
            self.logger.info(f"Позиция {symbol} уже закрыта")
            return True

        amt = abs(float(position['positionAmt']))
        actual_side = position.get('positionSide', position_side)

        try:
            close_side = 'SELL' if actual_side.upper() == "LONG" else 'BUY'
            params = {
                'symbol': base_symbol,
                'side': close_side,
                'positionSide': actual_side.upper(),
                'type': 'MARKET',
                'quantity': str(amt)
            }
            data = self._request("/openApi/swap/v2/trade/order", params)
            self.logger.info(f"Позиция {symbol} закрыта, ID: {data.get('orderId')}")
            return True

        except Exception as e:
            error_msg = str(e).lower()
            if '101204' in error_msg or 'insufficient margin' in error_msg:
                self.logger.error(f"Ошибка маржи 101204 для {symbol}, пробуем fallback")
                return self._fallback_close_position(symbol, actual_side, amt)
            raise

    def _fallback_close_position(self, symbol: str, position_side: str, quantity: float) -> bool:
        base_symbol = symbol.replace('/USDT', '-USDT')
        try:
            self.logger.warning(f"Fallback закрытие {symbol}")
            close_side = 'SELL' if position_side.upper() == "LONG" else 'BUY'
            params = {
                'symbol': base_symbol,
                'side': close_side,
                'positionSide': position_side.upper(),
                'type': 'MARKET',
                'quantity': str(quantity)
            }
            try:
                params['reduceOnly'] = 'true'
                data = self._request("/openApi/swap/v2/trade/order", params)
                self.logger.info(f"Fallback успешен для {symbol}")
                return True
            except:
                del params['reduceOnly']
                data = self._request("/openApi/swap/v2/trade/order", params)
                self.logger.info(f"Fallback (без reduceOnly) успешен для {symbol}")
                return True
        except Exception as e:
            self.logger.error(f"Fallback не сработал для {symbol}: {e}")
            return False

    def _get_min_notional(self, symbol: str) -> float:
        try:
            market = self.exchange.market(symbol)
            return float(market['limits']['cost']['min'] or 5.0)
        except:
            return 5.0

    def place_market_order(self, symbol: str, side: str, position_side: str,
                          quantity: float, stop_loss: float = None,
                          take_profit: float = None) -> Dict:
        base_symbol = symbol.replace('/USDT', '-USDT')
        price_precision = self._get_price_precision(symbol)
        qty_precision = self._get_qty_precision(symbol)
        min_notional = self._get_min_notional(symbol)

        ticker = self.get_ticker(symbol)
        current_price = float(ticker.get('lastPrice', 0))

        order_value = quantity * current_price
        if order_value < min_notional and current_price > 0:
            quantity = (min_notional * 1.05) / current_price

        qty_str = str(round(quantity, qty_precision))

        params = {
            'symbol': base_symbol,
            'side': side.upper(),
            'positionSide': position_side.upper(),
            'type': 'MARKET',
            'quantity': qty_str
        }

        if stop_loss is not None and stop_loss > 0:
            params['stopLoss'] = self._format_stop_obj(stop_loss, price_precision, "STOP_MARKET")
        if take_profit is not None and take_profit > 0:
            params['takeProfit'] = self._format_stop_obj(take_profit, price_precision, "TAKE_PROFIT_MARKET")

        try:
            data = self._request("/openApi/swap/v2/trade/order", params)
            return {"orderId": data.get('orderId'), "symbol": symbol, "side": side, "quantity": quantity}
        except Exception as e:
            self.logger.error(f"Ошибка ордера {symbol} {side}: {e}")
            raise

    def place_market_buy(self, symbol: str, quote_order_qty: float, position_side: str,
                         stop_loss: float = None, take_profit: float = None) -> Dict:
        ticker = self.get_ticker(symbol)
        price = float(ticker.get('lastPrice', 0))
        if price <= 0:
            raise ValueError(f"Не удалось получить цену для {symbol}")
        quantity = quote_order_qty / price
        return self.place_market_order(symbol, 'BUY', position_side, quantity, stop_loss, take_profit)

    def place_market_sell(self, symbol: str, quantity: float, position_side: str,
                          stop_loss: float = None, take_profit: float = None) -> Dict:
        return self.place_market_order(symbol, 'SELL', position_side, quantity, stop_loss, take_profit)

